import typing as t

class dataclass:
    def __init__(self, **kwargs: t.Any) -> None:
        for key, value in kwargs.items():
            setattr(self, key, value)

    def __repr__(self) -> str:
        args = []
        for key, value in self.__dict__.items():
            if key.startswith('_') and key.endswith('__'):
                continue
            args.append(f"{key}={value!r}")
        return f"{type(self).__name__}({', '.join(args)})"

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, type(self)):
            return NotImplemented
        return self.__dict__ == other.__dict__

    def __hash__(self) -> int:
        return hash(tuple(sorted(self.__dict__.items())))

class field:
    def __init__(self, default: t.Any = ..., metadata: t.Any = None) -> None:
        self.default = default
        self.metadata = metadata

    def __get__(self, instance: object, owner: type) -> t.Any:
        if instance is None:
            return self
        return instance.__dict__[self.name]

    def __set__(self, instance: object, value: t.Any) -> None:
        instance.__dict__[self.name] = value

    def __set_name__(self, owner: type, name: str) -> None:
        self.name = name

class dataclasses(t.Protocol):
    @classmethod
    def __config__(cls, **kwargs: t.Any) -> None:
        pass

    def __post_init__(self: t.Any) -> None:
        pass

def dataclasses.field(*args: t.Any, **kwargs: t.Any) -> field:
    return field(*args, **kwargs)

def dataclasses.dataclass(*args: t.Any, **kwargs: t.Any) -> type:
    def decorator(cls: type) -> type:
        cls.__config__(*args, **kwargs)
        return cls
    return decorator

