class LoggingFormatChecker(Plugin):
    name = "logging_format"
    version = "0.1"
    log_level = logging.WARNING
    options = (
        options.BooleanOption(
            shortstop='H',
            longstop='--logging-format',
            help='Check logging format strings',
            default=False
        ),
    )

    def match(self, tree, line_number, column_number, text):
        if not self._options.logging_format:
            return None
        return re.match(r'logging\.(?:debug|info|warning|error|critical)\(.*\)', text)

    def leave_FuncDef(self, node, used):
        if 'logging' in node.name:
            for arg in node.args.args:
                if arg.arg == 'format':
                    self.add_error(
                        messages.Message(
                            line_number=node.lineno,
                            column_number=node.col_offset,
                            text='W9001: Missing logging format string',
                            severity=self.log_level
                        )
                    )

    def leave_Call(self, node, used):
        if 'logging' in node.name:
            for arg in node.args.args:
                if arg.arg == 'format':
                    if not re.match(r'%\([a-zA-Z]+\)s', arg.value):
                        self.add_error(
                            messages.Message(
                                line_number=node.lineno,
                                column_number=node.col_offset,
                                text='W9002: Improper logging format string',
                                severity=self.log_level
                            )
                        )

