import random

def retry_decorator(attempts, delay):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt < attempts - 1:
                        time.sleep(delay + random.uniform(0, delay))
                        print(f"Attempt {attempt + 1} failed. Retrying in {delay + random.uniform(0, delay)} seconds.")
                    else:
                        raise e
        return wrapper
    return decorator
